using System.Collections;
using UnityEngine;
using UnityEngine.InputSystem;

public class PlayerController : MonoBehaviour
{
    [SerializeField] private Transform bottomLeftTile;
    [SerializeField] private Vector2Int gridSize = new(3, 3);
    [SerializeField] private Vector2Int startCell = new(1, 1);
    [SerializeField] private Vector2 cellSpacing = Vector2.one;
    [SerializeField] private float moveDuration = 0.2f;
    [SerializeField] private float jumpHeight = 0.35f;

    private Vector2Int currentCell;
    private bool isMoving;
    private float baseZ;

    private void Start()
    {
        baseZ = transform.position.z;

        if (bottomLeftTile == null)
        {
            var tile = GameObject.Find("BottomLeft");
            if (tile != null)
            {
                bottomLeftTile = tile.transform;
            }
        }

        if (bottomLeftTile == null)
        {
            Debug.LogError("PlayerController needs a BottomLeft tile reference.", this);
            enabled = false;
            return;
        }

        currentCell = ClampToGrid(startCell);
        transform.position = CellToWorld(currentCell);
    }

    private void Update()
    {
        if (isMoving)
        {
            return;
        }

        Vector2Int move = ReadMoveInput();
        if (move == Vector2Int.zero)
        {
            return;
        }

        Vector2Int nextCell = currentCell + move;
        if (!IsInsideGrid(nextCell))
        {
            return;
        }

        StartCoroutine(JumpToCell(nextCell));
    }

    private Vector2Int ReadMoveInput()
    {
        Keyboard keyboard = Keyboard.current;
        if (keyboard == null)
        {
            return Vector2Int.zero;
        }

        if (keyboard.wKey.wasPressedThisFrame || keyboard.upArrowKey.wasPressedThisFrame)
        {
            return Vector2Int.up;
        }

        if (keyboard.sKey.wasPressedThisFrame || keyboard.downArrowKey.wasPressedThisFrame)
        {
            return Vector2Int.down;
        }

        if (keyboard.aKey.wasPressedThisFrame || keyboard.leftArrowKey.wasPressedThisFrame)
        {
            return Vector2Int.left;
        }

        if (keyboard.dKey.wasPressedThisFrame || keyboard.rightArrowKey.wasPressedThisFrame)
        {
            return Vector2Int.right;
        }

        return Vector2Int.zero;
    }

    private IEnumerator JumpToCell(Vector2Int targetCell)
    {
        isMoving = true;

        Vector3 startPosition = transform.position;
        Vector3 endPosition = CellToWorld(targetCell);
        float duration = Mathf.Max(0.0001f, moveDuration);
        float elapsed = 0f;

        while (elapsed < duration)
        {
            elapsed += Time.deltaTime;
            float t = Mathf.Clamp01(elapsed / duration);

            Vector3 position = Vector3.Lerp(startPosition, endPosition, t);
            position.y += Mathf.Sin(t * Mathf.PI) * jumpHeight;
            transform.position = position;

            yield return null;
        }

        currentCell = targetCell;
        transform.position = endPosition;
        isMoving = false;
    }

    private Vector3 CellToWorld(Vector2Int cell)
    {
        Vector3 anchor = bottomLeftTile.position;
        return new Vector3(
            anchor.x + (cell.x * cellSpacing.x),
            anchor.y + (cell.y * cellSpacing.y),
            baseZ);
    }

    private Vector2Int ClampToGrid(Vector2Int cell)
    {
        return new Vector2Int(
            Mathf.Clamp(cell.x, 0, gridSize.x - 1),
            Mathf.Clamp(cell.y, 0, gridSize.y - 1));
    }

    private bool IsInsideGrid(Vector2Int cell)
    {
        return cell.x >= 0 && cell.x < gridSize.x &&
               cell.y >= 0 && cell.y < gridSize.y;
    }
}

