+    [SerializeField, Range(0f, 1f)] private float parryWindowMinNormalizedSize = 0.35f;
+    [SerializeField, Range(0f, 1f)] private float parryWindowMaxNormalizedSize = 0.55f;
+    [SerializeField] private bool logParryAttempts = true;
