using System.Linq;
using UnityEditor;
using UnityEditor.Animations;
using UnityEditor.SceneManagement;
using UnityEngine;

public static class SetupKimuraIdleAnimation
{
    private const string SourceAssetPath = "Assets/Art/Character/KimuraSpriteSheets/kimuraidleSheet.aseprite";
    private const string GeneratedClipPath = "Assets/Art/Character/KimuraSpriteSheets/PlayerKimuraIdle.anim";
    private const string GeneratedControllerPath = "Assets/Art/Character/KimuraSpriteSheets/PlayerKimuraIdle.controller";
    private const string ScenePath = "Assets/Scenes/Main.unity";

    [MenuItem("Tools/Tiger Samurai/Apply Kimura Idle Animation")]
    public static void ApplyToMainPlayer()
    {
        AnimationClip sourceClip = FindSourceClip();
        if (sourceClip == null)
        {
            Debug.LogError($"Could not find an imported AnimationClip at {SourceAssetPath}.");
            return;
        }

        ObjectReferenceKeyframe[] spriteFrames = ExtractSpriteFrames(sourceClip);
        if (spriteFrames.Length == 0)
        {
            Debug.LogError($"Could not extract sprite frames from {sourceClip.name}.");
            return;
        }

        AnimationClip idleClip = CreateOrUpdateIdleClip(sourceClip, spriteFrames);
        AnimatorController controller = CreateOrUpdateController(idleClip);

        ApplyToPlayer(controller, spriteFrames);

        AssetDatabase.SaveAssets();
        Debug.Log("Applied Kimura idle animation to Player.");
    }

    private static AnimationClip FindSourceClip()
    {
        Object[] subAssets = AssetDatabase.LoadAllAssetsAtPath(SourceAssetPath);
        return subAssets
            .OfType<AnimationClip>()
            .FirstOrDefault(clip => clip.name == "kimuraidleSheet")
            ?? subAssets.OfType<AnimationClip>().FirstOrDefault();
    }

    private static ObjectReferenceKeyframe[] ExtractSpriteFrames(AnimationClip sourceClip)
    {
        EditorCurveBinding binding = AnimationUtility
            .GetObjectReferenceCurveBindings(sourceClip)
            .FirstOrDefault(curve => curve.propertyName == "m_Sprite");

        if (binding.propertyName != "m_Sprite")
        {
            return System.Array.Empty<ObjectReferenceKeyframe>();
        }

        return AnimationUtility.GetObjectReferenceCurve(sourceClip, binding);
    }

    private static AnimationClip CreateOrUpdateIdleClip(AnimationClip sourceClip, ObjectReferenceKeyframe[] spriteFrames)
    {
        AnimationClip idleClip = AssetDatabase.LoadAssetAtPath<AnimationClip>(GeneratedClipPath);
        if (idleClip == null)
        {
            idleClip = new AnimationClip();
            AssetDatabase.CreateAsset(idleClip, GeneratedClipPath);
        }

        idleClip.frameRate = sourceClip.frameRate;

        foreach (EditorCurveBinding binding in AnimationUtility.GetObjectReferenceCurveBindings(idleClip))
        {
            AnimationUtility.SetObjectReferenceCurve(idleClip, binding, null);
        }

        var spriteBinding = new EditorCurveBinding
        {
            path = string.Empty,
            type = typeof(SpriteRenderer),
            propertyName = "m_Sprite"
        };

        AnimationUtility.SetObjectReferenceCurve(idleClip, spriteBinding, spriteFrames);

        var settings = AnimationUtility.GetAnimationClipSettings(idleClip);
        settings.loopTime = true;
        AnimationUtility.SetAnimationClipSettings(idleClip, settings);

        EditorUtility.SetDirty(idleClip);
        return idleClip;
    }

    private static AnimatorController CreateOrUpdateController(AnimationClip idleClip)
    {
        AnimatorController controller = AssetDatabase.LoadAssetAtPath<AnimatorController>(GeneratedControllerPath);
        if (controller == null)
        {
            controller = AnimatorController.CreateAnimatorControllerAtPath(GeneratedControllerPath);
        }

        AnimatorStateMachine stateMachine = controller.layers[0].stateMachine;
        AnimatorState idleState = stateMachine.states
            .Select(childState => childState.state)
            .FirstOrDefault(state => state.name == "Idle");

        if (idleState == null)
        {
            idleState = stateMachine.AddState("Idle");
        }

        idleState.motion = idleClip;
        stateMachine.defaultState = idleState;

        EditorUtility.SetDirty(controller);
        return controller;
    }

    private static void ApplyToPlayer(AnimatorController controller, ObjectReferenceKeyframe[] spriteFrames)
    {
        var scene = EditorSceneManager.OpenScene(ScenePath);
        GameObject player = GameObject.Find("Player");
        if (player == null)
        {
            Debug.LogError("Could not find a GameObject named Player in Main.unity.");
            return;
        }

        PlayerController playerController = player.GetComponent<PlayerController>();
        Animator animator = player.GetComponent<Animator>();
        PlayerIdleAnimator idleAnimator = player.GetComponent<PlayerIdleAnimator>();
        SpriteRenderer spriteRenderer = player.GetComponent<SpriteRenderer>();

        if (playerController == null || spriteRenderer == null)
        {
            Debug.LogError("Player needs both PlayerController and SpriteRenderer components.");
            return;
        }

        if (animator == null)
        {
            animator = player.AddComponent<Animator>();
        }

        if (idleAnimator == null)
        {
            idleAnimator = player.AddComponent<PlayerIdleAnimator>();
        }

        animator.runtimeAnimatorController = controller;
        idleAnimator.Configure(playerController);

        Sprite firstSprite = spriteFrames[0].value as Sprite;
        if (firstSprite != null)
        {
            spriteRenderer.sprite = firstSprite;
        }

        EditorUtility.SetDirty(animator);
        EditorUtility.SetDirty(idleAnimator);
        EditorUtility.SetDirty(spriteRenderer);
        EditorSceneManager.SaveScene(scene);
    }
}

